const headers = $input.first().json.headers || {};
const body = $input.first().json.body || $input.first().json;

const eventType = headers['x-github-event'] || headers['X-GitHub-Event'] || '';
const action = body.action || '';

// Loop prevention: skip if opened/labeled and the 'synced-by:n8n' label is present
if ((action === 'opened' || action === 'labeled') && eventType === 'issues') {
  const labels = (body.issue?.labels || []).map(l => l.name);
  if (labels.includes('synced-by:n8n')) {
    return [];
  }
}

const issue = body.issue || body.pull_request || {};
const issueNumber = issue.number || null;
const title = issue.title || '';
const state = issue.state || 'open';
const bodyText = issue.body || '';
const labels = (issue.labels || []).map(l => l.name);
const milestoneNumber = issue.milestone?.number || null;
const merged = body.pull_request?.merged || false;
const prUrl = body.pull_request?.html_url || null;

return [{
  json: {
    eventType,
    action,
    issueNumber,
    title,
    state,
    body: bodyText,
    labels,
    milestoneNumber,
    merged,
    prUrl,
    rawBody: body
  }
}];

const item = $input.first().json;

// Skip if not merged
if (!item.merged) {
  return [];
}

// Extract linked issue numbers from PR body using common closing keywords
// Matches: Closes #N, Fixes #N, Resolves #N (case-insensitive)
const bodyText = item.body || '';
const pattern = /(?:close[sd]?|fix(?:e[sd])?|resolve[sd]?)\s*#(\d+)/gi;
const linkedIssues = [];
let match;
while ((match = pattern.exec(bodyText)) !== null) {
  linkedIssues.push(parseInt(match[1], 10));
}

return [{
  json: {
    ...item,
    linkedIssues,
    opStatusId: 12, // Closed
    opComment: `Closed via PR merge: ${item.prUrl}`
  }
}];

const item = $input.first().json;
const { state, labels } = item;

// Map GitHub state + labels to OP status_id
// OP status IDs: 1=New, 7=In Progress, 12=Closed
let opStatusId = 1; // New by default
if (state === 'closed') {
  opStatusId = 12; // Closed
} else if (labels.includes('in-progress') || labels.includes('status:in-progress')) {
  opStatusId = 7; // In Progress
}

// Map GitHub labels to OP properties
const opUpdate = {
  statusId: opStatusId,
  subject: item.title,
  description: item.body,
  ghIssueNumber: item.issueNumber,
  milestoneNumber: item.milestoneNumber
};

return [{ json: { ...item, opUpdate } }];
